<template>
  <section data-test="rate-guard-panel" :class="['rate-guard-panel', { 'is-automation-target': automationTarget }]">
    <div class="guard-left">
      <label class="guard-switch" :class="{ 'is-on': enabled }"><input data-test="rate-guard-enabled" type="checkbox" :checked="enabled" @change="emitEnabled" /><span /></label>
      <div><div class="guard-title">{{ t('admin.upstreamAccounts.rateGuardTitle') }}</div><div class="guard-description">{{ t('admin.upstreamAccounts.rateGuardDescription') }}</div>
        <div class="guard-status-line"><span :class="['status-pill', enabled ? 'status-pill-on' : 'status-pill-muted']">{{ enabled ? t('admin.upstreamAccounts.rateGuardEnabled') : t('admin.upstreamAccounts.rateGuardDisabled') }}</span><span>{{ t('admin.upstreamAccounts.rateGuardLastRun') }}: {{ lastRunText }}</span><span v-if="config?.last_run_status" :class="['record-status', config.last_run_status === 'failed' ? 'record-status-error' : 'record-status-success']">{{ config.last_run_status === 'failed' ? t('admin.upstreamAccounts.rateGuardStatusFailed') : t('admin.upstreamAccounts.rateGuardStatusSuccess') }}</span><span v-if="config?.last_run_message" class="status-error-message">{{ config.last_run_message }}</span><span v-if="ignoredCount" class="guard-ignore-pill"><Icon name="shield" size="xs" :stroke-width="2" />{{ t('admin.upstreamAccounts.rateGuardIgnoredSummary', { count: ignoredCount }) }}</span></div>
      </div>
    </div>
    <div v-if="unhandledSyncLogCount" class="guard-sync-log-warning"><Icon name="exclamationTriangle" size="md" :stroke-width="2" /><div><strong>{{ t('admin.upstreamAccounts.unhandledSyncLogs', '待处理同步日志') }} {{ unhandledSyncLogCount }}</strong><span>{{ t('admin.upstreamAccounts.unhandledSyncLogsDescription', '有低倍率分组解绑记录需要确认处理') }}</span></div><button class="ui-button warning" data-test="rate-guard-open-logs" @click="$emit('open-logs')">{{ t('admin.upstreamAccounts.openSyncLogs', '打开同步日志') }}</button></div>
    <div class="guard-controls"><span class="control-label">{{ t('admin.upstreamAccounts.rateGuardAutoRun') }} {{ t('admin.upstreamAccounts.rateGuardIntervalSeconds') }}</span><input data-test="rate-guard-interval" type="number" min="1" class="ui-input" :value="intervalSeconds" @input="emitInterval" /><span class="guard-hint">{{ dailyRunsText }}</span>
      <div class="guard-ignore-control"><span class="control-label">{{ t('admin.upstreamAccounts.rateGuardIgnoredAccounts') }}</span><button class="guard-ignore-summary" :class="{ 'is-empty': !ignoredCount, 'is-invalid': ignoredInputInvalid }" :disabled="loading || saving" data-test="rate-guard-ignored-manage" @click="$emit('manage-ignored')"><Icon name="shield" size="xs" :stroke-width="2" /><span>{{ ignoredSummaryText }}</span></button><button class="ui-button small" :disabled="loading || saving" data-test="rate-guard-ignored-manage-button" @click="$emit('manage-ignored')">{{ t('admin.upstreamAccounts.rateGuardIgnoredManage') }}</button></div>
      <button class="ui-button" :disabled="loading || saving" data-test="rate-guard-save" @click="$emit('save')">{{ t('common.save') }}</button><button class="ui-button primary" :disabled="loading || saving || running" data-test="rate-guard-run" @click="$emit('run')"><Icon name="play" size="sm" :stroke-width="2" :class="running ? 'animate-pulse' : ''" />{{ t('admin.upstreamAccounts.rateGuardRunNow') }}</button>
    </div>
  </section>
</template>
<script setup lang="ts">
import { useI18n } from 'vue-i18n'
import type { UpstreamAccountRateGuardConfig } from '@/api/admin/upstreamAccountSync'
import Icon from '@/components/icons/Icon.vue'
defineProps<{ enabled: boolean; intervalSeconds: number; config: UpstreamAccountRateGuardConfig | null; lastRunText: string; dailyRunsText: string; ignoredCount: number; ignoredSummaryText: string; ignoredInputInvalid: boolean; loading: boolean; saving: boolean; running: boolean; unhandledSyncLogCount: number; automationTarget: boolean }>()
const emit = defineEmits<{ 'update:enabled': [boolean]; 'update:intervalSeconds': [number]; 'manage-ignored': []; 'open-logs': []; save: []; run: [] }>()
const { t } = useI18n()
function emitEnabled(event: Event) { emit('update:enabled', (event.target as HTMLInputElement).checked) }
function emitInterval(event: Event) { emit('update:intervalSeconds', Number((event.target as HTMLInputElement).value)) }
</script>
<style scoped>
