dius:8px;padding:0 12px}.ui-button,.guard-ignore-summary{min-height:38px;border:1px solid #e5e7eb;border-radius:8px;background:#fff;padding:0 14px;font-weight:600}.primary{border-color:#059669;background:#059669;color:#fff}.warning{border-color:#f59e0b;color:#b45309}.small,.guard-ignore-summary{min-height:28px;padding:4px 8px;font-size:12px}.guard-ignore-summary{max-width:260px;border-color:#c7d2fe;border-radius:999px;background:#eef2ff;color:#4338ca}.guard-ignore-summary.is-invalid{border-color:#fecaca;background:#fef2f2;color:#b91c1c}@media(max-width:1023px){.rate-guard-panel{grid-template-columns:1fr}.guard-controls{justify-content:flex-start}}@media(max-width:768px){.rate-guard-panel{gap:8px;padding:10px}.guard-description,.guard-hint{display:none}.guard-controls{display:grid;grid-template-columns:auto 92px 1fr}.guard-ignore-control{grid-column:1/-1}.guard-switch,.guard-switch span{width:36px;height:20px}.guard-switch span:after{top:2px;left:2px;width:16px;height:16px}.guard-switch.is-on span:after{transform:translateX(16px)}}
